    map['amount'] = Variable<double>(amount);
    map['status'] = Variable<String>(status);
    if (!nullToAbsent || paidDate != null) {
      map['paid_date'] = Variable<DateTime>(paidDate);
    }
    if (!nullToAbsent || receiptNumber != null) {
      map['receipt_number'] = Variable<String>(receiptNumber);
    }
    if (!nullToAbsent || collectorId != null) {
      map['collector_id'] = Variable<int>(collectorId);
    }
    map['penalty_amount'] = Variable<double>(penaltyAmount);
    map['partial_paid_amount'] = Variable<double>(partialPaidAmount);
    return map;
  }

  InstallmentsCompanion toCompanion(bool nullToAbsent) {
    return InstallmentsCompanion(
      id: Value(id),
      contractId: Value(contractId),
      dueDate: Value(dueDate),
      amount: Value(amount),
      status: Value(status),
      paidDate: paidDate == null && nullToAbsent
          ? const Value.absent()
          : Value(paidDate),
      receiptNumber: receiptNumber == null && nullToAbsent
          ? const Value.absent()
          : Value(receiptNumber),
      collectorId: collectorId == null && nullToAbsent
          ? const Value.absent()
          : Value(collectorId),
      penaltyAmount: Value(penaltyAmount),
      partialPaidAmount: Value(partialPaidAmount),
    );
  }

